// // This module is designed to capture and hold a 10-bit input value when disabled. On the falling edge of the clock, if the reset (rst) signal is low, the output (q) remains unchanged. Otherwise, if the enable (en) signal is deasserted, the current input (d) is transferred to the output (q).
module top_module(
                      input [9:0] d,
                      input clk,
                      input rst,
                      input en,
                      output reg [9:0] q
                      );always @(posedge clk or posedge rst) begin
      if(rst) q <= 0;
      else if(en) q <= d;
   end
endmodule
